css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #030b1a; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 72px; border-bottom: 1px solid rgba(255,255,255,0.07); }
.logo { font-size: 22px; font-weight: 800; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.nav-right { display: flex; gap: 10px; }
.login { padding: 10px 20px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: white; font-weight: 600; cursor: pointer; }
.try { padding: 10px 20px; border-radius: 10px; border: none; background: #3b82f6; color: white; font-weight: 700; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 72px); }
.tag { display: inline-block; color: #60a5fa; font-size: 13px; font-weight: 700; margin-bottom: 20px; }
h1 { font-size: 72px; font-weight: 900; line-height: 1; letter-spacing: -3px; margin-bottom: 20px; } h1 span { background: linear-gradient(135deg, #3b82f6, #06b6d4); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.hero-content p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 28px; max-width: 460px; }
.search-course { display: flex; gap: 0; margin-bottom: 18px; max-width: 480px; }
.search-course input { flex: 1; height: 52px; border-radius: 14px 0 0 14px; border: 1px solid rgba(255,255,255,0.12); border-right: none; background: rgba(255,255,255,0.06); color: white; padding: 0 18px; font-size: 15px; outline: none; }
.search-course button { height: 52px; padding: 0 24px; border-radius: 0 14px 14px 0; border: none; background: #3b82f6; color: white; font-weight: 700; cursor: pointer; white-space: nowrap; }
.popular-tags { display: flex; gap: 10px; align-items: center; flex-wrap: wrap; } .popular-tags span { color: #6b7280; font-size: 13px; } .popular-tags a { color: #60a5fa; text-decoration: none; font-size: 13px; font-weight: 600; background: rgba(59,130,246,0.1); padding: 4px 12px; border-radius: 20px; }
.course-card.featured { background: rgba(255,255,255,0.05); border: 1px solid rgba(59,130,246,0.3); border-radius: 20px; padding: 24px; margin-bottom: 16px; position: relative; }
.cc-badge { position: absolute; top: 16px; right: 16px; background: #eab308; color: #0a0800; padding: 4px 10px; border-radius: 20px; font-size: 11px; font-weight: 800; }
.cc-thumb { font-size: 48px; margin-bottom: 16px; }
.course-card h3 { font-size: 18px; font-weight: 700; margin-bottom: 12px; }
.cc-meta { display: flex; gap: 16px; font-size: 13px; color: #9ca3af; margin-bottom: 16px; }
.cc-instructor { display: flex; align-items: center; gap: 10px; margin-bottom: 16px; font-size: 14px; color: #9ca3af; }
.inst-avatar { width: 28px; height: 28px; border-radius: 50%; background: linear-gradient(135deg, #3b82f6, #8b5cf6); display: flex; align-items: center; justify-content: center; font-size: 11px; font-weight: 800; color: white; }
.cc-bottom { display: flex; justify-content: space-between; align-items: center; }
.cc-price { font-size: 24px; font-weight: 900; }
.cc-btn { padding: 10px 20px; border-radius: 10px; border: none; background: #3b82f6; color: white; font-weight: 700; cursor: pointer; }
.course-mini-list { display: flex; flex-direction: column; gap: 10px; }
.cml-item { display: flex; align-items: center; gap: 14px; padding: 14px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; cursor: pointer; transition: all 0.2s; } .cml-item:hover { border-color: rgba(59,130,246,0.3); }
.cml-icon { font-size: 28px; } .cml-item div strong { display: block; font-size: 14px; margin-bottom: 2px; } .cml-item div span { color: #6b7280; font-size: 12px; }
.categories { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.07); } .categories h2 { font-size: 42px; font-weight: 800; margin-bottom: 36px; }
.cat-grid { display: grid; grid-template-columns: repeat(6, 1fr); gap: 16px; }
.cat-card { padding: 24px 16px; border-radius: 16px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); text-align: center; cursor: pointer; transition: all 0.2s; } .cat-card:hover { border-color: rgba(59,130,246,0.4); transform: translateY(-3px); }
.cat-icon { font-size: 32px; margin-bottom: 10px; } .cat-card strong { display: block; font-size: 14px; font-weight: 700; margin-bottom: 4px; } .cat-card span { color: #6b7280; font-size: 12px; }

js:
document.querySelector('.search-course button').addEventListener('click', function() { const q = document.querySelector('.search-course input').value; if (q) alert('"' + q + '" için kurslar aranıyor...'); });
document.querySelector('.search-course input').addEventListener('keydown', function(e) { if (e.key === 'Enter') document.querySelector('.search-course button').click(); });
document.querySelector('.cc-btn').addEventListener('click', function() { this.textContent = '✓ Eklendi'; this.style.background = '#22c55e'; setTimeout(() => { this.textContent = 'Kayıt Ol'; this.style.background = '#3b82f6'; }, 2000); });
